import{heroGraphData,mobileGraphData,howItWorksGraphData,nodeColors}from"./graph-config.js";function debounce(fn,delay){let timeout;return(...args)=>{clearTimeout(timeout);timeout=setTimeout(()=>fn(...args),delay)}}function getNodeColor(group){return nodeColors[group]||"#0066FF"}export function initializeHeroGraph(){const canvas=document.getElementById("hero-graph-canvas");if(!canvas)return;const width=canvas.clientWidth||window.innerWidth;const height=canvas.clientHeight||600;const context=canvas.getContext("2d");if(!context)return;const isMobile=window.innerWidth<768;const data=isMobile?mobileGraphData:heroGraphData;const pixelRatio=Math.min(window.devicePixelRatio||1,2);canvas.width=width*pixelRatio;canvas.height=height*pixelRatio;context.scale(pixelRatio,pixelRatio);const simulation=d3.forceSimulation(data.nodes).force("link",d3.forceLink(data.links).id(d=>d.id).distance(d=>d.distance||80)).force("charge",d3.forceManyBody().strength(isMobile?-150:-300)).force("collide",isMobile?null:d3.forceCollide().radius(35)).force("center",d3.forceCenter(width/2,height/2));let angle=0;const rotationSpeed=5e-4;simulation.on("tick",()=>{context.fillStyle="rgba(15, 20, 25, 0.05)";context.fillRect(0,0,width,height);angle+=rotationSpeed;const rotation=angle%(2*Math.PI);context.strokeStyle="rgba(255, 255, 255, 0.15)";context.lineWidth=2;data.links.forEach(link=>{const cx=width/2;const cy=height/2;const cos=Math.cos(rotation);const sin=Math.sin(rotation);const sx=link.source.x-cx;const sy=link.source.y-cy;const rotatedSx=sx*cos-sy*sin+cx;const rotatedSy=sx*sin+sy*cos+cy;const tx=link.target.x-cx;const ty=link.target.y-cy;const rotatedTx=tx*cos-ty*sin+cx;const rotatedTy=tx*sin+ty*cos+cy;context.beginPath();context.moveTo(rotatedSx,rotatedSy);context.lineTo(rotatedTx,rotatedTy);context.stroke()});data.nodes.forEach(node=>{const cx=width/2;const cy=height/2;const cos=Math.cos(rotation);const sin=Math.sin(rotation);const x=node.x-cx;const y=node.y-cy;const rotatedX=x*cos-y*sin+cx;const rotatedY=x*sin+y*cos+cy;context.beginPath();context.arc(rotatedX,rotatedY,15,0,2*Math.PI);const color=getNodeColor(node.group);context.fillStyle=color;context.fill();context.strokeStyle="#FFFFFF";context.lineWidth=2;context.stroke()})});window.addEventListener("resize",debounce(()=>{const newWidth=canvas.clientWidth;const newHeight=canvas.clientHeight;canvas.width=newWidth*pixelRatio;canvas.height=newHeight*pixelRatio;context.scale(pixelRatio,pixelRatio);simulation.force("center",d3.forceCenter(newWidth/2,newHeight/2))},300));return simulation}export function initializeHowItWorksGraph(){const canvas=document.getElementById("how-it-works-graph-canvas");if(!canvas)return;const width=canvas.clientWidth||400;const height=400;const context=canvas.getContext("2d");if(!context)return;const pixelRatio=Math.min(window.devicePixelRatio||1,2);canvas.width=width*pixelRatio;canvas.height=height*pixelRatio;context.scale(pixelRatio,pixelRatio);const simulation=d3.forceSimulation(howItWorksGraphData.nodes).force("link",d3.forceLink(howItWorksGraphData.links).id(d=>d.id).distance(60)).force("charge",d3.forceManyBody().strength(-100)).force("center",d3.forceCenter(width/2,height/2));simulation.on("tick",()=>{context.fillStyle="rgba(15, 20, 25, 1)";context.fillRect(0,0,width,height);context.strokeStyle="rgba(255, 255, 255, 0.15)";context.lineWidth=2;howItWorksGraphData.links.forEach(link=>{context.beginPath();context.moveTo(link.source.x,link.source.y);context.lineTo(link.target.x,link.target.y);context.stroke()});howItWorksGraphData.nodes.forEach(node=>{context.beginPath();context.arc(node.x,node.y,12,0,2*Math.PI);const color=getNodeColor(node.group);context.fillStyle=color;context.fill();context.strokeStyle="#FFFFFF";context.lineWidth=2;context.stroke()})});window.addEventListener("resize",debounce(()=>{const newWidth=canvas.clientWidth;canvas.width=newWidth*pixelRatio;canvas.height=height*pixelRatio;context.scale(pixelRatio,pixelRatio);simulation.force("center",d3.forceCenter(newWidth/2,height/2))},300));return simulation}